/**
 * 工具系统类型定义
 */

export interface ToolCallInput {
  tool_id: string;
  tool_name: string;
  arguments: Record<string, unknown>;
}

export interface ToolCallOutput {
  tool_id: string;
  tool_name: string;
  result: unknown;
  result_for_assistant?: string;
  is_error: boolean;
  duration_ms?: number;
  from_cache?: boolean;
}

export interface ToolDefinition {
  name: string;
  description: string;
  input_schema: {
    type: "object";
    properties: Record<string, unknown>;
    required?: string[];
  };
}

/**
 * 验证结果 - 对标Rust的ValidationResult
 */
export interface ValidationResult {
  result: boolean;
  message?: string;
  error_code?: number;
  meta?: unknown;
}

/**
 * 工具渲染选项
 */
export interface ToolRenderOptions {
  verbose?: boolean;
}

/**
 * 扩展的工具上下文 - 对标Rust的ToolUseContext
 */
export interface ToolContext {
  /** 会话ID */
  session_id: string;
  /** 轮次ID */
  turn_id: string;
  /** Turn索引（用于快照系统） */
  turn_index?: number;
  /** 工具调用ID */
  tool_call_id?: string;
  /** 消息ID */
  message_id?: string;
  /** Agent类型 */
  agent_type?: string;
  /** 工作区路径 */
  workspace_path?: string;
  /** 取消信号 */
  signal?: AbortSignal;
  /** 安全模式 */
  safe_mode?: boolean;
  /** 文件读取时间戳映射 */
  read_file_timestamps?: Map<string, number>;
}

export type ToolExecutionStatus = "pending" | "executing" | "completed" | "failed" | "cancelled";

export interface ToolExecutionState {
  tool_id: string;
  tool_name: string;
  status: ToolExecutionStatus;
  start_time: number;
  end_time?: number;
  result?: ToolCallOutput;
  error?: string;
}

/**
 * 工具接口 - 对标Rust的Tool trait
 */
export interface Tool {
  /**
   * 工具名称（唯一标识）
   */
  name: string;

  /**
   * 工具描述
   */
  description: string;

  /**
   * 获取工具定义（供 AI 模型使用）
   */
  get_definition(): ToolDefinition;

  /**
   * 执行工具
   */
  execute(input: ToolCallInput, context: ToolContext): Promise<ToolCallOutput>;

  /**
   * 是否为终止轮次的工具（如 SwitchMode, Task 等）
   */
  is_end_turn_tool(): boolean;

  /**
   * 是否为并发安全的工具
   * 并发安全的工具可以与其他并发安全的工具同时执行
   * 非并发安全的工具（如文件写入操作）需要串行执行
   */
  is_concurrency_safe(): boolean;

  /**
   * 是否为只读工具
   * 只读工具不会修改文件系统或系统状态
   */
  is_readonly(): boolean;

  /**
   * 是否需要权限确认
   * 对标Rust的 needs_permissions
   */
  needs_permissions?(input?: Record<string, unknown>): boolean;

  /**
   * 验证输入参数
   * 对标Rust的 validate_input
   */
  validate_input?(input: Record<string, unknown>, context?: ToolContext): Promise<ValidationResult>;

  /**
   * 渲染结果给助手
   * 对标Rust的 render_result_for_assistant
   */
  render_result_for_assistant?(output: unknown): string;

  /**
   * 渲染工具使用消息
   * 对标Rust的 render_tool_use_message
   */
  render_tool_use_message?(input: Record<string, unknown>, options?: ToolRenderOptions): string;

  /**
   * 是否支持流式输出
   * 对标Rust的 supports_streaming
   */
  supports_streaming?(): boolean;
}

/**
 * 工具事件数据（匹配 Rust 版本格式）
 */
export type ToolEventData =
  | {
      event_type: "EarlyDetected";
      tool_id: string;
      tool_name: string;
    }
  | {
      event_type: "ParamsPartial";
      tool_id: string;
      tool_name: string;
      params: string;
    }
  | {
      event_type: "Queued";
      tool_id: string;
      tool_name: string;
      position: number;
    }
  | {
      event_type: "Waiting";
      tool_id: string;
      tool_name: string;
      dependencies: string[];
    }
  | {
      event_type: "Started";
      tool_id: string;
      tool_name: string;
      params: Record<string, unknown>;
    }
  | {
      event_type: "Progress";
      tool_id: string;
      tool_name: string;
      message: string;
      percentage: number;
    }
  | {
      event_type: "Streaming";
      tool_id: string;
      tool_name: string;
      chunks_received: number;
    }
  | {
      event_type: "StreamChunk";
      tool_id: string;
      tool_name: string;
      data: unknown;
    }
  | {
      event_type: "ConfirmationNeeded";
      tool_id: string;
      tool_name: string;
      params: Record<string, unknown>;
    }
  | {
      event_type: "Confirmed";
      tool_id: string;
      tool_name: string;
    }
  | {
      event_type: "Rejected";
      tool_id: string;
      tool_name: string;
    }
  | {
      event_type: "Completed";
      tool_id: string;
      tool_name: string;
      result: unknown;
      duration_ms: number;
      from_cache: boolean;
    }
  | {
      event_type: "Failed";
      tool_id: string;
      tool_name: string;
      error: string;
    }
  | {
      event_type: "Cancelled";
      tool_id: string;
      tool_name: string;
      reason: string;
    };
